//Making a calulator using JavaScript

function add(a, b) {
    return a + b;
}

function subtract(a, b) {
    return a - b;
}

function multiply(a, b) {
    return a * b;
}

function divide(a, b) {
    if (b === 0) {
        return "Cannot divide by zero";
    }
    return a / b;
}

//making calender using JavaScript

function getCurrentDate() {
    const date = new Date();
    return date.toDateString();
}